        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Vendors Overview",
            Slug = "vendors-overview",
            Summary = "What vendors are, how to manage them, payment terms, and how vendors connect to purchase orders and inventory.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/vendors"]""",
            Tags = """["vendors","procurement"]""",
            ContentJson = """{"body":"## Vendors Overview\n\nThe Vendors module is your centralized supplier directory. It tracks every company you buy from — raw material suppliers, tooling vendors, service providers, and subcontractors — along with their contact information, addresses, payment terms, and purchase history.\n\n### What Is a Vendor?\n\nA vendor is any external company or individual you purchase goods or services from. Each vendor record stores:\n- **Company name** — the legal or trade name of the supplier\n- **Contact information** — primary contact name, email, and phone number\n- **Address** — street address, city, state, ZIP code, and country\n- **Payment terms** — negotiated terms like Net 30, Net 60, Due on Receipt, etc.\n- **Active/Inactive status** — whether you currently do business with this vendor\n\n### How Vendors Connect to Other Features\n\n**Purchase Orders:** Every purchase order is linked to a vendor. When you create a PO, you select the vendor, and the PO inherits the vendor's address and payment terms. The vendor detail view shows a complete PO history so you can see all orders placed with a supplier.\n\n**Inventory and Receiving:** When materials arrive, receiving records tie back to the PO and its vendor. This gives you full traceability: which vendor supplied which materials, when they arrived, and whether they met quality standards.\n\n**Vendor Scorecard:** Each vendor has a performance scorecard that tracks on-time delivery percentage, quality acceptance rate, quantity accuracy, and total spend. Vendors receive an overall score and letter grade (A through F) based on weighted criteria: Delivery (40%), Quality (30%), Price (20%), and Quantity (10%).\n\n**Accounting Integration:** When QuickBooks or another accounting system is connected, vendor records sync automatically. Once connected, vendors can no longer be edited here — you make changes in the accounting system instead. When no accounting system is connected, you have full control to add, edit, and remove vendors.\n\n### When to Use Vendors\n\n- When onboarding a new supplier before placing your first PO\n- When updating contact information or payment terms for an existing supplier\n- When reviewing a vendor's delivery and quality performance via the scorecard\n- When deactivating a vendor you no longer do business with (records are preserved)\n- When looking up PO history to see what you've ordered from a specific supplier","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
