            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/vendors"]""",
            Tags = """["vendors","walkthrough","procurement"]""",
            ContentJson = """{"appRoute":"/vendors","startButtonLabel":"Tour Vendors","steps":[{"element":"[data-testid='new-vendor-btn']","popover":{"title":"New Vendor Button","description":"Click here to add a vendor. You'll first pick how to set it up: Quick add (just the company name and basic contact — fill in the rest later) or Guided setup (a step-by-step wizard for strategic or approved vendors that also captures classification, address, terms, and the parts they supply). The rest of this tour covers Quick add.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Vendors","description":"Type to find a vendor by company name, contact, email, or phone. The list filters on its own a moment after you stop typing, or press Enter to apply it right away.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Show All vendors, only Active ones, or only Inactive ones. Inactive vendors stay for history but don't show up when you pick a vendor for a purchase order.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Vendors Table","description":"This lists every vendor that matches your search and filter. You'll see each one's company name, contact, email, phone, active status, order count, and when it was added. Click a heading to sort, or click a row to open the vendor's details.","side":"top"}},{"element":"app-data-table thead th:nth-child(6)","popover":{"title":"PO Count Column","description":"Shows how many purchase orders you've placed with each vendor, so you can tell at a glance how often you order from them without opening their details.","side":"bottom"}}]}"""
