            AppRoutes = """["/vendors"]""",
            Tags = """["vendors","quiz","procurement"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"vn1","text":"You need to onboard a new raw material supplier before placing your first purchase order. What is the correct first step?","options":[{"id":"a","text":"Go to Purchase Orders and create a PO — the vendor will be auto-created"},{"id":"b","text":"Navigate to Vendors, click New Vendor, then pick a setup path (Quick add or Guided setup) and fill in at least the company name","isCorrect":true},{"id":"c","text":"Add the supplier to Inventory as a new storage location"},{"id":"d","text":"Go to Admin → Reference Data and add the vendor as a lookup value"}],"explanation":"New suppliers must be created in the Vendors module first. Click New Vendor in the page header — you then choose Quick add (needs only the company name to start) or Guided setup (a step-by-step wizard for strategic or approved vendors). Either way, the only required field is Company Name; the vendor then becomes available in PO vendor dropdowns."},{"id":"vn2","text":"Which field is the only required field when creating a new vendor?","options":[{"id":"a","text":"Contact Name"},{"id":"b","text":"Email"},{"id":"c","text":"Company Name","isCorrect":true},{"id":"d","text":"Payment Terms"}],"explanation":"Company Name is the only required field on the vendor form. All other fields — contact name, email, phone, address, payment terms, and notes — are optional."},{"id":"vn3","text":"A vendor's scorecard shows a grade of 'C' with an overall score of 68/100. What does this tell you?","options":[{"id":"a","text":"The vendor has been deactivated due to poor performance"},{"id":"b","text":"The vendor is performing below average based on weighted criteria: delivery (40%), quality (30%), price (20%), and quantity accuracy (10%)","isCorrect":true},{"id":"c","text":"The vendor has only completed a few POs and doesn't have enough data for a full evaluation"},{"id":"d","text":"The vendor's payment terms need to be renegotiated"}],"explanation":"The vendor scorecard grades performance on a 100-point scale using four weighted criteria: On-Time Delivery (40%), Quality Acceptance (30%), Price (20%), and Quantity Accuracy (10%). A 'C' grade with 68/100 indicates below-average performance across these areas."},{"id":"vn4","text":"You want to see all purchase orders placed with a specific vendor. Where do you find this?","options":[{"id":"a","text":"Go to Purchase Orders and filter by vendor name"},{"id":"b","text":"Click the vendor row to open the detail dialog, then select the Purchase Orders tab","isCorrect":true},{"id":"c","text":"Run a report in the Reports module filtered by vendor"},{"id":"d","text":"Check the vendor's Notes field for PO references"}],"explanation":"The vendor detail dialog has three tabs: Info, Purchase Orders, and Scorecard. The Purchase Orders tab shows a data table with all POs linked to that vendor, including PO number, status, expected delivery date, and creation date."},{"id":"vn5","text":"Your company just connected QuickBooks Online as the accounting provider. What happens to vendor management here?","options":[{"id":"a","text":"Nothing changes — vendors are managed independently in both systems"},{"id":"b","text":"Vendor management becomes read-only here — vendor records sync from QuickBooks, and edits must be made in the accounting system","isCorrect":true},{"id":"c","text":"All vendor records are deleted and replaced with QuickBooks data"},{"id":"d","text":"Vendors can only be created here and pushed to QuickBooks"}],"explanation":"When an accounting provider is connected, vendor management becomes read-only here. Vendor records sync from QuickBooks automatically. The vendor list, PO history, and scorecard remain fully functional — only direct editing is disabled."},{"id":"vn6","text":"You no longer do business with a supplier but want to preserve their purchase history. What should you do?","options":[{"id":"a","text":"Delete the vendor — PO history is retained separately"},{"id":"b","text":"Open the vendor detail, click the Deactivate button on the Info tab to set them as Inactive","isCorrect":true},{"id":"c","text":"Remove all POs associated with the vendor, then delete the vendor record"},{"id":"d","text":"Change the vendor's payment terms to 'Suspended'"}],"explanation":"Deactivating a vendor preserves the full record including all PO history, scorecard data, and contact information. The vendor simply won't appear in active vendor lists or PO vendor dropdowns. You can reactivate them later if needed."},{"id":"vn7","text":"What payment terms options are available when creating a vendor?","options":[{"id":"a","text":"Only Net 30 and Net 60"},{"id":"b","text":"Due on Receipt, Net 15, Net 30, Net 45, Net 60, and COD","isCorrect":true},{"id":"c","text":"Payment terms are free-text and can be anything"},{"id":"d","text":"Payment terms are set globally in Admin and cannot vary per vendor"}],"explanation":"The Payment Terms dropdown offers standard commercial terms: Due on Receipt, Net 15, Net 30, Net 45, Net 60, and COD (plus a blank 'none' option). These terms are inherited by new POs placed with the vendor."},{"id":"vn8","text":"How does the vendor search box apply your search term?","options":[{"id":"a","text":"It filters automatically a moment after you stop typing; pressing Enter applies it immediately","isCorrect":true},{"id":"b","text":"Search only works on the Company Name field — other fields are ignored"},{"id":"c","text":"You must select a status filter before the search will run"},{"id":"d","text":"Nothing happens until you have typed at least 3 characters"}],"explanation":"The vendor search filters automatically a moment after you stop typing; pressing Enter applies it immediately. It searches across company name, contact name, email, and phone fields. The status filter (All, Active, Inactive) works independently and does not need to be set before searching."},{"id":"vn9","text":"In the vendor detail dialog, what does the External ID field indicate?","options":[{"id":"a","text":"A vendor reference number you assign manually for internal tracking"},{"id":"b","text":"The vendor's tax identification number (EIN)"},{"id":"c","text":"An ID automatically populated when the vendor is synced from an accounting provider like QuickBooks","isCorrect":true},{"id":"d","text":"The vendor's customer number in their own system"}],"explanation":"The External ID is automatically populated when a vendor record is synced from an accounting provider (e.g., QuickBooks). It stores the provider's internal identifier for cross-reference. It is not user-editable and only appears when an accounting integration has synced the vendor."},{"id":"vn10","text":"Which factor carries the most weight in the vendor scorecard calculation?","options":[{"id":"a","text":"Quality Acceptance (30%)"},{"id":"b","text":"Price Competitiveness (20%)"},{"id":"c","text":"On-Time Delivery (40%)","isCorrect":true},{"id":"d","text":"Quantity Accuracy (10%)"}],"explanation":"The vendor scorecard uses four weighted criteria: On-Time Delivery carries the most weight at 40%, followed by Quality Acceptance at 30%, Price at 20%, and Quantity Accuracy at 10%. This reflects that reliable delivery is the most critical factor in vendor performance."}]}"""
